{"content":"1: import { betterer, BettererFileIssues } from '@betterer/betterer';
2: import Codeowners from 'codeowners';
3: import { readFile, writeFile } from 'fs/promises';
4: import { template } from 'lodash';
5: import path from 'path';
6: import { hideBin } from 'yargs/helpers';
7: import yargs from 'yargs/yargs';
8: 
9: const argv = yargs(hideBin(process.argv))
10:   .option('template', {
11:     demandOption: true,
12:     alias: 't',
13:     describe: 'Path to a template to use for each issue. See source bettererIssueTemplate.md for an example',
14:     type: 'string',
15:     default: './scripts/cli/bettererIssueTemplate.md',
16:   })
17:   .option('output', {
18:     demandOption: true,
19:     alias: 'o',
20:     describe: 'Path to directory to save issues to',
21:     type: 'string',
22:   })
23:   .option('test', {
24:     demandOption: true,
25:     alias: 'b',
26:     describe: 'Name of the betterer test to produce the report for',
27:     type: 'string',
28:   })
29:   .option('test-message', {
30:     alias: 'm',
31:     describe: 'Filter issues containing this message',
32:     type: 'string',
33:   })
34:   .option('single-owner', {
35:     type: 'boolean',
36:     alias: 's',
37:     describe: 'Only use first owner for files with multiple owners',
38:     default: false,
39:   })
40: 
41:   .usage('Usage: yarn betterer:issues -t [path] -o [path] -b [string]')
42:   .version(false)
43:   .help('help').argv;
44: 
45: interface FileDetails {
46:   fileName: string;
47:   issueCount: number;
48:   issues: BettererFileIssues;
49: }
50: 
51: // really dumb and simple pluralize function. not meant to be exhaustive
52: function plural(word: string, count: number) {
53:   if (count === 0 || count > 1) {
54:     return word + 's';
55:   }
56: 
57:   return word;
58: }
59: 
60: async function main() {
61:   const args = await argv;
62:   const templatePath = path.resolve(args.template);
63:   const outputPath = path.resolve(args.output);
64:   const templateString = (await readFile(templatePath)).toString();
65: 
66:   const owners = new Codeowners();
67:   const results = await betterer.results();
68: 
69:   const filesByOwner: Record<string, FileDetails[]> = {};
70: 
71:   for (const testResults of results.resultSummaries) {
72:     if (testResults.name !== args.test) {
73:       continue;
74:     }
75: 
76:     if (typeof testResults.details === 'string') {
77:       continue;
78:     }
79: 
80:     for (const _fileName in testResults.details) {
81:       const fileName = _fileName.replace(process.cwd() + '/', '');
82:       const _details = testResults.details[_fileName];
83:       let ownersForFile = owners.getOwner(fileName);
84: 
85:       if (args.singleOwner) {
86:         ownersForFile = [ownersForFile[0]];
87:       }
88: 
89:       const filterByMessage = args.testMessage?.length ? args.testMessage.toLowerCase() : undefined;
90: 
91:       const filteredDetails = filterByMessage
92:         ? _details.filter((v) => v.message.toLowerCase().includes(filterByMessage))
93:         : _details;
94: 
95:       const numberOfIssues = filteredDetails.length;
96: 
97:       if (numberOfIssues === 0) {
98:         continue;
99:       }
100: 
101:       for (const owner of ownersForFile) {
102:         if (!filesByOwner[owner]) {
103:           filesByOwner[owner] = [];
104:         }
105: 
106:         filesByOwner[owner].push({
107:           fileName,
108:           issueCount: numberOfIssues,
109:           issues: filteredDetails,
110:         });
111:       }
112:     }
113:   }
114: 
115:   const contexts = Object.entries(filesByOwner).map(([owner, files]) => {
116:     const fileCount = files.length;
117:     const totalIssueCount = files.reduce((acc, v) => acc + v.issueCount, 0);
118: 
119:     return {
120:       owner,
121:       files,
122:       fileCount,
123:       totalIssueCount,
124:       issueFilter: args.test,
125:       issueMessageFilter: args.testMessage,
126:     };
127:   });
128: 
129:   const compiledTemplate = template(templateString, { imports: { plural } });
130: 
131:   for (const context of contexts) {
132:     const fileSafeOwner = context.owner.replace(/[^a-z0-9-]/gi, '_');
133:     const fileSafeTestName = args.test.replace(/[^a-z0-9-]/gi, '_');
134:     const outputFilePath = path.join(outputPath, `${fileSafeTestName}_${fileSafeOwner}.txt`);
135:     const printed = compiledTemplate(context);
136:     await writeFile(outputFilePath, printed);
137: 
138:     const indented = printed
139:       .split('\n')
140:       .map((v) => `\t${v}`)
141:       .join('\n');
142: 
143:     console.log(`Printed issue for owner`, context.owner, 'to', outputFilePath);
144:     console.log(indented);
145:   }
146: }
147: 
148: main().catch(console.error);
